output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT(SUM(?gold) AS ?totalGold)(SUM(?silver) AS ?totalSilver)(SUM(?bronze) AS ?totalBronze)(SUM(?gold) + SUM(?silver) + SUM(?bronze) AS ?totalMedals) WHERE {
  VALUES ?eventType {
    wd:Q2020009 wd:Q2020010
  }
  ?event wdt:P31 ?eventType .
  ?event wdt:P10874 ?medalTable .
  ?medalTable wdt:P17 wd:Q16 ; wdt:P10657 ?gold ; wdt:P10655 ?silver ; wdt:P10654 ?bronze .
  FILTER(isNumeric(?gold) && isNumeric(?silver) && isNumeric(?bronze))
}
